def _resolve_dynamic_defaults(self, ctx: Context) -> None:
    """Resolve options whose ``default`` is a mapping of other
    option declarations to value maps (dynamic defaults). This runs
    after all sources (command line, environment variables,
    configuration files) have been consumed, so it can look at the
    final value of the options it depends on.

    Only options whose value still comes from
    :attr:`ParameterSource.DEFAULT` are affected; an explicitly
    provided value always wins.
    """
    params = self.get_params(ctx)

    for param in params:
        if not isinstance(param, Option) or param.dynamic_default is None:
            continue

        if ctx.get_parameter_source(param.name) is not ParameterSource.DEFAULT:  # type: ignore[arg-type]
            continue

        resolved = None

        for opt_name, mapping in param.dynamic_default.items():
            source_param = next(
                (
                    p
                    for p in params
                    if opt_name in p.opts or opt_name in p.secondary_opts
                ),
                None,
            )

            if source_param is None or source_param.name is None:
                continue

            key = str(ctx.params.get(source_param.name))

            if key in mapping:
                resolved = mapping[key]

        if resolved is not None:
            ctx.params[param.name] = param.process_value(ctx, resolved)  # type: ignore[index]

